#include<iostream>
using namespace std;
int main() {
	int n,a,b,s=0;
	cin>>n;
	string p;
	bool sp[4][13]= {0};
	for(int i=0; i<n; i++) {
		cin>>p;
		if(p[0]=='D') {
			a=0;
		} else if(p[0]=='C') {
			a=1;
		} else if(p[0]=='H') {
			a=2;
		} else if(p[0]=='S') {
			a=3;
		}
		if(p[1]=='A') {
			b=0;
		} else if(p[1]=='2') {
			b=1;
		} else if(p[1]=='3') {
			b=2;
		} else if(p[1]=='4') {
			b=3;
		} else if(p[1]=='5') {
			b=4;
		} else if(p[1]=='6') {
			b=5;
		} else if(p[1]=='7') {
			b=6;
		} else if(p[1]=='8') {
			b=7;
		} else if(p[1]=='9') {
			b=8;
		} else if(p[1]=='T') {
			b=9;
		} else if(p[1]=='J') {
			b=10;
		} else if(p[1]=='Q') {
			b=11;
		} else if(p[1]=='K') {
			b=12;
		}
		if(sp[a][b]==0) {
			s=s+1;
			sp[a][b]=1;
		}
	}
	cout<<52-s;
}
